practice_tasks.solution:
def sort_users(users):
    return sorted(users, key=lambda user: user["created_at"])

users = [
    {"name": "carol", "created_at": "2024-03-01"},
    {"name": "alice", "created_at": "2024-01-15"}
]
print(sort_users(users))

